import{_ as a,o as e,c as i,a2 as d}from"./chunks/framework.BWuWLRhz.js";const b=JSON.parse('{"title":"内置插件","description":"","frontmatter":{"title":"内置插件"},"headers":[],"relativePath":"rich-text/plugins.md","filePath":"rich-text/plugins.md"}'),l={name:"rich-text/plugins.md"};function r(o,t,n,h,s,c){return e(),i("div",null,[...t[0]||(t[0]=[d(`<h1 id="内置插件详解" tabindex="-1">内置插件详解 <a class="header-anchor" href="#内置插件详解" aria-label="Permalink to &quot;内置插件详解&quot;">​</a></h1><h2 id="文本格式插件" tabindex="-1">文本格式插件 <a class="header-anchor" href="#文本格式插件" aria-label="Permalink to &quot;文本格式插件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>插件</th><th>功能</th><th>快捷键</th></tr></thead><tbody><tr><td>Bold</td><td>加粗</td><td>Ctrl+B</td></tr><tr><td>Italic</td><td>斜体</td><td>Ctrl+I</td></tr><tr><td>Underline</td><td>下划线</td><td>Ctrl+U</td></tr><tr><td>Strikethrough</td><td>删除线</td><td>Ctrl+Shift+S</td></tr><tr><td>Code</td><td>行内代码</td><td>Ctrl+E</td></tr></tbody></table><h2 id="块级元素插件" tabindex="-1">块级元素插件 <a class="header-anchor" href="#块级元素插件" aria-label="Permalink to &quot;块级元素插件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>插件</th><th>功能</th></tr></thead><tbody><tr><td>Heading</td><td>标题 H1/H2/H3</td></tr><tr><td>Quote</td><td>引用块</td></tr><tr><td>List</td><td>有序/无序列表</td></tr><tr><td>Code Block</td><td>代码块（21 种语言语法高亮）</td></tr><tr><td>Table</td><td>表格（8x8 可视选择器）</td></tr></tbody></table><h2 id="富内容插件" tabindex="-1">富内容插件 <a class="header-anchor" href="#富内容插件" aria-label="Permalink to &quot;富内容插件&quot;">​</a></h2><h3 id="image-图片" tabindex="-1">Image（图片） <a class="header-anchor" href="#image-图片" aria-label="Permalink to &quot;Image（图片）&quot;">​</a></h3><ul><li>拖拽图片到编辑器上传</li><li>粘贴图片上传</li><li>支持缩放、对齐、标题编辑</li><li>存储使用 Active Storage</li></ul><h3 id="link-链接" tabindex="-1">Link（链接） <a class="header-anchor" href="#link-链接" aria-label="Permalink to &quot;Link（链接）&quot;">​</a></h3><ul><li>Ctrl+K 快捷插入</li><li>URL 自动验证</li><li>支持编辑和取消链接</li></ul><h3 id="video-视频" tabindex="-1">Video（视频） <a class="header-anchor" href="#video-视频" aria-label="Permalink to &quot;Video（视频）&quot;">​</a></h3><ul><li>支持 YouTube、Bilibili、Vimeo</li><li>粘贴 URL 自动转为 16:9 嵌入</li></ul><h3 id="attachment-附件" tabindex="-1">Attachment（附件） <a class="header-anchor" href="#attachment-附件" aria-label="Permalink to &quot;Attachment（附件）&quot;">​</a></h3><ul><li>文件上传，支持拖拽</li><li>文件图标颜色按类型区分</li></ul><h3 id="mention-提及" tabindex="-1">Mention（提及） <a class="header-anchor" href="#mention-提及" aria-label="Permalink to &quot;Mention（提及）&quot;">​</a></h3><ul><li>输入 <code>@</code> 触发用户搜索</li><li>键盘导航选择</li></ul><h3 id="emoji-表情" tabindex="-1">Emoji（表情） <a class="header-anchor" href="#emoji-表情" aria-label="Permalink to &quot;Emoji（表情）&quot;">​</a></h3><ul><li>输入 <code>:</code> 触发表情选择器</li><li>8 个分类，128 个表情</li></ul><h2 id="图表与公式插件" tabindex="-1">图表与公式插件 <a class="header-anchor" href="#图表与公式插件" aria-label="Permalink to &quot;图表与公式插件&quot;">​</a></h2><h3 id="mermaid-图表" tabindex="-1">Mermaid（图表） <a class="header-anchor" href="#mermaid-图表" aria-label="Permalink to &quot;Mermaid（图表）&quot;">​</a></h3><p>在编辑器中插入 Mermaid 代码块，自动渲染：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>graph TD</span></span>
<span class="line"><span>  A[开始] --&gt; B{判断}</span></span>
<span class="line"><span>  B --&gt;|是| C[执行]</span></span>
<span class="line"><span>  B --&gt;|否| D[结束]</span></span></code></pre></div><p>支持：流程图、序列图、甘特图、类图等。</p><h3 id="math-数学公式" tabindex="-1">Math（数学公式） <a class="header-anchor" href="#math-数学公式" aria-label="Permalink to &quot;Math（数学公式）&quot;">​</a></h3><p>使用 KaTeX 渲染数学公式：</p><ul><li>行内公式：<code>$E = mc^2$</code></li><li>块级公式：<code>$$\\int_a^b f(x)dx$$</code></li></ul><p>输入 LaTeX 代码，实时预览渲染结果。</p><h2 id="其他插件" tabindex="-1">其他插件 <a class="header-anchor" href="#其他插件" aria-label="Permalink to &quot;其他插件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>插件</th><th>功能</th></tr></thead><tbody><tr><td>History</td><td>撤销 (Ctrl+Z) / 重做 (Ctrl+Y)</td></tr><tr><td>Slash Commands</td><td>输入 <code>/</code> 触发命令菜单，9 种命令</td></tr></tbody></table>`,29)])])}const m=a(l,[["render",r]]);export{b as __pageData,m as default};
